import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function DriverDashboard() {
  const [tasks, setTasks] = useState([]);
  const navigate = useNavigate();

  const getTasks = async () => {
    try {
      const res = await axios.get(
        "http://localhost:3000/api/driver/today-task"
      );

      setTasks(res.data.requests);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getTasks();
  }, []);

  return (
    <div className="min-h-screen bg-[#4CBB17]/10 p-8">
      {/* Header */}

      <div className="mb-10 text-center">
        <h1 className="text-5xl font-extrabold text-green-900">
          Today's Tasks
        </h1>

        <p className="text-gray-600 mt-2">
          Scheduled emergency pickup requests
        </p>
      </div>

      {tasks.length === 0 ? (
        <div className="bg-white p-10 rounded-2xl shadow text-center">
          <h2 className="text-2xl font-bold text-gray-500">
            No Tasks Available
          </h2>
        </div>
      ) : (
        <div className="space-y-5">
          {tasks.map((task) => (
            <div
              key={task._id}
              className="bg-white rounded-2xl shadow-lg p-6 flex justify-between items-center"
            >
              <div>
                <h2 className="text-xl font-bold text-green-800">
                  📍 {task.location?.location}
                </h2>

                <p className="mt-2">
                  👤 {task.requestedBy?.name}
                </p>

                <p>
                  📞 {task.requestedBy?.mobile}
                </p>

                <p>
                  🕒 {task.scheduledTime}
                </p>
              </div>

              <button
                onClick={() =>
                  navigate(`/driver-route/${task._id}`)
                }
                className="bg-green-600 hover:bg-green-700 text-white px-8 py-3 rounded-xl font-semibold"
              >
                Start Route
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
